#!/bin/sh
# Commands equivalent to this certification run.
# Generated by `cavs certify` — reproduce by running them in order.
set -e

cavs signature export --raw dataset/Build_v1 -o artifacts/old.cavssig
cavs signature export --raw dataset/Build_v2 -o artifacts/new.cavssig
cavs diff-plan dataset/Build_v1 dataset/Build_v2 --out artifacts/update.cavsplan
cavs apply --old dataset/Build_v1 --plan artifacts/update.cavsplan --out <tmp> --verify
cavs plan-update --to dataset/Build_v2 --client-state 'cold-install' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'cold-cache,has-previous-install' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'warm-cache,has-previous-install' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'has-previous-install' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'has-previous-install,low-ram' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'has-previous-install,slow-hdd' --policy balanced --json
cavs plan-update --from dataset/Build_v1 --to dataset/Build_v2 --client-state 'has-previous-install,low-disk' --policy balanced --json
cavs bench routes --old dataset/Build_v1 --new dataset/Build_v2 --include-pairwise-proxy --out artifacts/route-bench
cavs analyze steampipe dataset/Build_v1 dataset/Build_v2 --out steampipe-style.md
cavs analyze-packs dataset/Build_v1 dataset/Build_v2 --out pack-analysis.md
cavs io-estimate dataset/Build_v1 dataset/Build_v2 --out io-estimate.md
